import { useEffect, useState } from "react";
import { backgroundimages } from "../../Shared/globals";
import Navbar from "../../Shared/Navbar";
import { FlatButton } from "../../Shared/FlatButton";
import { Space } from "antd";

export const Header = () => {
  const [currentIndex, setCurrentIndex] = useState(0);

  useEffect(() => {
    const interval = setInterval(() => {
      setCurrentIndex((prevIndex) => (prevIndex + 1) % backgroundimages.length);
    }, 4000); 

    return () => clearInterval(interval); 
  }, []);

  const styles = {
    container:{
      color:'white',
      height:"90vh"
    },
    content:{
      display:"flex",
      justifyContent:'center',
      alignItems:'center',
      height:"100%"
    },
  
  }

  const currentBackground = backgroundimages[currentIndex].background;
  
  return (
    <section>
      <div
        className="header-background"
        style={{
          backgroundImage: `url(${currentBackground})`
        }}
      >
        <div className="header-gradient-background" >

        <div className="container-fluid" style={styles.container}>
          <div style={{...styles.content, flexDirection:'column'}}>
          <h1>
          Making a difference one heart, one life at a time.
          </h1>
          <p>
          The Trinity Arms Foundation is a charity organisation 
          registered in the united Kingdom committed to making a lasting impact both locally and beyond. 
          </p>
          <Space wrap={true}>
            <FlatButton title="Learn more" className="buttondark" onClick={()=>console.log('clicked')}/>
            <FlatButton title="Get involved" className="buttondark" onClick={()=>console.log('clicked')}/>
            <FlatButton title="Donate now" className="buttonsuccess" onClick={()=>console.log('clicked')}/>
          </Space>
          </div>
        </div>
        </div>
      </div>
    </section>
  );
};
